     3→import { RescueCallbacks, RescuePayload, RescueStatus } from '../models';
     4→import { getParticipantIdFromToken } from '../utils/participantId';
     5→
     6→export async function performRescue(
     7→  payload: RescuePayload,
     8→  callbacks?: RescueCallbacks,
     9→): Promise<void> {
    10→  const { rescueActions } = useRootStore.getState();
    11→
    12→  try {
    13→    rescueActions.setStatus(RescueStatus.LOADING);
    14→
    15→    const participantId =
    16→      payload.participantId || (await getParticipantIdFromToken());
    17→    const rescuePayload: RescuePayload = {
    18→      ...payload,
    19→      participantId,
    20→    };
    21→
    22→    const response = await rescueApi.rescue(rescuePayload);
    23→
    24→    const rawStatus = (response?.status ?? response?.data?.status) as
    25→      | { message: string }
    26→      | undefined;
    27→
    28→    if (!rawStatus) {
    29→      rescueActions.setResponseStatus(rawStatus);
    30→      rescueActions.setStatus(RescueStatus.ERROR);
    31→      callbacks?.onFailed?.(rawStatus);
    32→      return;
    33→    }
    34→
    35→    const isSuccess = rawStatus?.message?.toLowerCase() === 'success';
    36→
    37→    if (isSuccess) {
